/**
 * Claude Code Plugin: Knowledge System
 * 一键初始化知识库并自动探索代码库
 */

const { exec } = require('child_process');
const { promisify } = require('util');
const path = require('path');

const execAsync = promisify(exec);

module.exports = async function initExplore(args, context) {
  const { workspace, agent, log, skill } = context;
  const projectRoot = workspace.rootPath;

  log.info('🚀 开始初始化知识库系统...');
  log.info(`项目路径: ${projectRoot}`);

  try {
    // ==========================================
    // 步骤 1: 运行 knowledge-init
    // ==========================================
    log.info('');
    log.info('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    log.info('📦 [1/3] 初始化知识库系统...');
    log.info('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

    const initResult = await execAsync('knowledge-init', {
      cwd: projectRoot,
      env: { ...process.env, PATH: `${process.env.HOME}/.local/bin:${process.env.PATH}` }
    });

    log.success('✓ 知识库系统初始化完成');
    log.info('  创建了以下文件:');
    log.info('    • docs/exploration/README.md');
    log.info('    • CLAUDE.md');
    log.info('    • scripts/update-knowledge.sh');
    log.info('    • .git/hooks/pre-commit');
    log.info('    • .github/workflows/update-knowledge.yml');

    // ==========================================
    // 步骤 2: 运行深度探索
    // ==========================================
    log.info('');
    log.info('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    log.info('🔍 [2/3] 运行代码库深度探索...');
    log.info('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    log.info('');
    log.info('预计耗时: 10-30 分钟');
    log.info('探索内容:');
    log.info('  • 项目结构扫描');
    log.info('  • 架构层次分析');
    log.info('  • 领域知识提取');
    log.info('  • 学习路径生成');
    log.info('');

    // 使用配置决定探索方式
    const explorerType = context.settings.explorerType || 'explore';

    if (explorerType === 'understand-anything') {
      // 使用 Understand-Anything agents
      log.info('使用 Understand-Anything agents 进行深度探索...');

      // 1. Project Scanner
      log.info('');
      log.info('▶ 扫描项目结构...');
      const scanResult = await agent({
        subagent_type: 'understand-anything:project-scanner',
        description: 'Scan project structure',
        prompt: `Scan this project and provide a comprehensive overview. Save results to ${projectRoot}/docs/exploration/project-scan.json`
      });
      log.success('✓ 项目扫描完成');

      // 2. Architecture Analyzer
      log.info('');
      log.info('▶ 分析架构设计...');
      const archResult = await agent({
        subagent_type: 'understand-anything:architecture-analyzer',
        description: 'Analyze architecture',
        prompt: `Analyze the architecture of this project and create a detailed document at ${projectRoot}/docs/exploration/02-architecture-analysis.md`
      });
      log.success('✓ 架构分析完成');

      // 3. Domain Analyzer
      log.info('');
      log.info('▶ 提取领域知识...');
      const domainResult = await agent({
        subagent_type: 'understand-anything:domain-analyzer',
        description: 'Extract domain knowledge',
        prompt: `Extract domain knowledge and technical details. Save to ${projectRoot}/docs/exploration/03-domain-knowledge.md`
      });
      log.success('✓ 领域知识提取完成');

      // 4. Tour Builder (Learning Path)
      log.info('');
      log.info('▶ 生成学习路径...');
      const tourResult = await agent({
        subagent_type: 'understand-anything:tour-builder',
        description: 'Generate learning path',
        prompt: `Create a guided learning tour for this project. Save to ${projectRoot}/docs/exploration/04-learning-path.md`
      });
      log.success('✓ 学习路径生成完成');

    } else {
      // 使用通用 Explore agent
      log.info('使用 Explore agent 进行探索...');
      log.info('');

      const exploreResult = await agent({
        subagent_type: 'Explore',
        description: 'Explore codebase',
        prompt: `Perform a comprehensive analysis of this codebase and generate knowledge documentation in ${projectRoot}/docs/exploration/.

Please create the following documents:

1. 01-project-overview.md
   - Project statistics (file counts, languages)
   - Directory structure
   - Core features
   - Main components

2. 02-architecture-analysis.md
   - Architecture layers
   - Module relationships
   - Design patterns
   - Mermaid diagrams

3. 03-domain-knowledge.md
   - Core concepts
   - Technical details
   - Key algorithms
   - Best practices

4. 04-learning-path.md
   - Step-by-step learning guide
   - Practice exercises
   - Checkpoint tests

Make the documentation comprehensive, well-structured, and include code examples.`
      });

      log.success('✓ 代码库探索完成');
    }

    // ==========================================
    // 步骤 3: 更新索引
    // ==========================================
    log.info('');
    log.info('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    log.info('📋 [3/3] 更新知识库索引...');
    log.info('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

    const updateResult = await execAsync('./scripts/update-knowledge.sh update', {
      cwd: projectRoot
    });

    log.success('✓ 索引更新完成');

    // ==========================================
    // 完成总结
    // ==========================================
    log.info('');
    log.info('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    log.success('✅ 知识库系统初始化和探索完成！');
    log.info('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    log.info('');
    log.info('生成的文档:');

    // 列出生成的文档
    const listResult = await execAsync('./scripts/update-knowledge.sh list', {
      cwd: projectRoot
    });
    log.info(listResult.stdout);

    log.info('');
    log.info('下一步:');
    log.info('  • 查看文档: cat docs/exploration/01-project-overview.md');
    log.info('  • 查看索引: cat docs/exploration/README.md');
    log.info('  • 查看 CLAUDE.md: cat CLAUDE.md');
    log.info('  • 列出文档: /knowledge list');
    log.info('');

    return {
      success: true,
      message: '知识库系统初始化和探索完成',
      docsPath: path.join(projectRoot, 'docs/exploration')
    };

  } catch (error) {
    log.error('❌ 错误: ' + error.message);
    log.error(error.stack);

    return {
      success: false,
      error: error.message
    };
  }
};

