{
  "name": "knowledge-system",
  "version": "1.0.0",
  "description": "Knowledge management system with auto-exploration",
  "author": "Knowledge System",
  "commands": {
    "init-explore": {
      "description": "Initialize knowledge base and run deep exploration",
      "handler": "init-explore.js"
    },
    "knowledge": {
      "description": "Manage knowledge documents",
      "handler": "knowledge.js"
    }
  },
  "settings": {
    "autoExplore": {
      "type": "boolean",
      "default": true,
      "description": "Automatically run exploration after init"
    },
    "explorerType": {
      "type": "string",
      "default": "explore",
      "enum": ["explore", "understand-anything"],
      "description": "Type of agent to use for exploration"
    }
  }
}

